from dataclasses import dataclass, field
from typing import Dict, Any, Optional


@dataclass
class MetadataOptions:
    agent_name: Optional[str] = None
    language: Optional[str] = None
    entrypoint: Optional[str] = None
    port: Optional[int] = None
    build_mode: Optional[str] = None
    description: Optional[str] = None
    output: Optional[str] = None

    def from_options(self) -> Dict[str, Any]:
        result = {}
        for key, value in self.__dict__.items():
            if value is not None:
                result[key] = value
        return result

import os
import re
import shutil
from typing import Optional, Dict, Any
from pathlib import Path

from agentcube.models.pack_models import MetadataOptions
from agentcube.services.metadata_service import MetadataService, AgentMetadata


class PackRuntime:
    def pack(self, workspace: str, options: MetadataOptions) -> Dict[str, Any]:
        workspace_path = self._prepare_output_path(workspace)
        self._validate_workspace_structure(workspace_path)
        metadata = self._load_or_create_metadata(workspace_path)
        self._apply_option_overrides(metadata, options)
        self._validate_language_compatibility(metadata, workspace_path)
        self._process_dependencies(metadata, workspace_path)
        self._generate_dockerfile(metadata, workspace_path)
        self._infer_entrypoint(metadata, workspace_path)
        self._update_pack_metadata(metadata, workspace_path)

        return {
            "agent_name": metadata.agent_name,
            "workspace_path": str(workspace_path),
            "metadata_path": str(workspace_path / "agent_metadata.yaml"),
        }

    def _validate_workspace_structure(self, workspace_path: Path) -> None:
        if not workspace_path.exists():
            raise ValueError(f"Workspace directory does not exist: {workspace_path}")
        if not workspace_path.is_dir():
            raise ValueError(f"Workspace path is not a directory: {workspace_path}")

    def _load_or_create_metadata(self, workspace_path: Path) -> AgentMetadata:
        metadata_service = MetadataService(workspace_path)

        for filename in ["agent_metadata.yaml", "agent.yaml", "metadata.yaml"]:
            metadata_path = workspace_path / filename
            if metadata_path.exists():
                return metadata_service.load_metadata()

        return AgentMetadata(
            agent_name=workspace_path.name,
            language="python",
            build_mode="local",
            port=8080,
        )

    def _apply_option_overrides(self, metadata: AgentMetadata, options: MetadataOptions) -> None:
        for key, value in options.from_options().items():
            if hasattr(metadata, key) and value is not None:
                setattr(metadata, key, value)

    def _validate_language_compatibility(self, metadata: AgentMetadata, workspace_path: Path) -> None:
        if metadata.language == "python":
            self._validate_python_compatibility(workspace_path)
        elif metadata.language == "java":
            self._validate_java_compatibility(workspace_path)

    def _validate_python_compatibility(self, workspace_path: Path) -> None:
        py_files = list(workspace_path.glob("*.py"))
        if not py_files:
            raise ValueError("No Python files found in workspace")

    def _validate_java_compatibility(self, workspace_path: Path) -> None:
        pom_file = workspace_path / "pom.xml"
        if not pom_file.exists():
            raise ValueError("Java workspace must contain pom.xml")

    def _process_dependencies(self, metadata: AgentMetadata, workspace_path: Path) -> None:
        if metadata.language == "python":
            self._process_python_dependencies(workspace_path)
        elif metadata.language == "java":
            self._process_java_dependencies(workspace_path)

    def _process_python_dependencies(self, workspace_path: Path) -> None:
        requirements = workspace_path / "requirements.txt"
        if not requirements.exists():
            with open(requirements, "w") as f:
                f.write("fastapi>=0.100.0\nuvicorn>=0.23.0\n")

    def _process_java_dependencies(self, workspace_path: Path) -> None:
        pass

    def _generate_dockerfile(self, metadata: AgentMetadata, workspace_path: Path) -> None:
        if metadata.language == "python":
            self._generate_python_dockerfile(metadata, workspace_path)
        elif metadata.language == "java":
            self._generate_java_dockerfile(metadata, workspace_path)
        else:
            raise ValueError(f"Unsupported language: {metadata.language}")

    def _generate_python_dockerfile(self, metadata: AgentMetadata, workspace_path: Path) -> None:
        dockerfile_content = f"""FROM python:3.11-slim

WORKDIR /app

COPY requirements.txt .
RUN pip install --no-cache-dir -r requirements.txt

COPY . .

EXPOSE {metadata.port}

CMD ["python", "-m", "{metadata.entrypoint or 'main'}"]
"""
        with open(workspace_path / "Dockerfile", "w") as f:
            f.write(dockerfile_content)

    def _generate_java_dockerfile(self, metadata: AgentMetadata, workspace_path: Path) -> None:
        dockerfile_content = f"""FROM maven:3.9-eclipse-temurin-17

WORKDIR /app

COPY pom.xml .
RUN mvn dependency:go-offline

COPY . .

RUN mvn package -DskipTests

EXPOSE {metadata.port}

CMD ["java", "-jar", "target/*.jar"]
"""
        with open(workspace_path / "Dockerfile", "w") as f:
            f.write(dockerfile_content)

    def _update_pack_metadata(self, metadata: AgentMetadata, workspace_path: Path) -> None:
        metadata_service = MetadataService(workspace_path)
        metadata_service.save_metadata(metadata)

    def _prepare_output_path(self, workspace: str) -> Path:
        return Path(workspace).resolve()

    def _infer_entrypoint(self, metadata: AgentMetadata, workspace_path: Path) -> None:
        if metadata.entrypoint:
            return

        if metadata.language == "python":
            main_py = workspace_path / "main.py"
            if main_py.exists():
                metadata.entrypoint = "main"
            else:
                py_files = list(workspace_path.glob("*.py"))
                if py_files:
                    entry_file = py_files[0].stem
                    metadata.entrypoint = entry_file
        elif metadata.language == "java":
            metadata.entrypoint = "target/*.jar"

import os
from typing import Optional, Dict, Any
from pathlib import Path

from agentcube.services.metadata_service import MetadataService
from agentcube.services.docker_service import DockerService
from agentcube.services.k8s_provider import KubernetesProvider
from agentcube.services.agentcube_provider import AgentCubeProvider


class PublishRuntime:
    def publish(self, workspace: str, version: Optional[str] = None, 
                image_url: Optional[str] = None, image_username: Optional[str] = None,
                image_password: Optional[str] = None, description: Optional[str] = None,
                region: Optional[str] = None, cloud_provider: Optional[str] = None,
                provider: str = "agentcube", node_port: Optional[int] = None,
                replicas: Optional[int] = None, namespace: Optional[str] = None) -> Dict[str, Any]:
        workspace_path = Path(workspace).resolve()
        metadata_service = MetadataService(workspace_path)
        metadata = metadata_service.load_metadata()

        if version:
            metadata.version = version
        if description:
            metadata.description = description

        image_ref = self._prepare_image_for_publishing(
            metadata, image_url, image_username, image_password
        )

        if provider == "agentcube":
            agentcube_provider = AgentCubeProvider()
            result = agentcube_provider.deploy_agent_runtime(metadata, image_ref, namespace)
        elif provider == "k8s":
            k8s_provider = KubernetesProvider()
            result = k8s_provider.deploy_agent(
                metadata=metadata,
                image=image_ref,
                node_port=node_port,
                replicas=replicas,
                namespace=namespace or "default",
            )
        else:
            raise ValueError(f"Unsupported provider: {provider}")

        self._update_publish_metadata(metadata, workspace_path, result)

        return {"status": "published", **result}

    def _prepare_image_for_publishing(self, metadata, image_url: Optional[str],
                                       image_username: Optional[str], 
                                       image_password: Optional[str]) -> str:
        if image_url:
            return image_url

        image_name = metadata.agent_name or "agentcube-agent"
        image_tag = metadata.version or "latest"

        docker_service = DockerService()
        local_image = f"{image_name}:{image_tag}"

        if metadata.build_mode == "local":
            if image_username and image_password:
                docker_service._docker_login_sdk(image_url, image_username, image_password)
                docker_service.push_image(local_image, image_url)
                return f"{image_url}:{image_tag}"

        return local_image

    def _prepare_local_image(self, metadata) -> str:
        image_name = metadata.agent_name or "agentcube-agent"
        image_tag = metadata.version or "latest"
        return f"{image_name}:{image_tag}"

    def _prepare_cloud_image(self, metadata, cloud_provider: Optional[str]) -> str:
        raise NotImplementedError(f"Cloud image preparation not implemented for: {cloud_provider}")

    def _publish_cr_to_k8s(self, metadata, image_ref: str) -> Dict[str, Any]:
        agentcube_provider = AgentCubeProvider()
        return agentcube_provider.deploy_agent_runtime(metadata, image_ref)

    def _publish_k8s(self, metadata, image_ref: str, node_port: Optional[int],
                     replicas: Optional[int], namespace: str) -> Dict[str, Any]:
        k8s_provider = KubernetesProvider()
        return k8s_provider.deploy_agent(
            metadata=metadata,
            image=image_ref,
            node_port=node_port,
            replicas=replicas,
            namespace=namespace,
        )

    def _update_publish_metadata(self, metadata, workspace_path: Path, 
                                  publish_result: Dict[str, Any]) -> None:
        metadata_service = MetadataService(workspace_path)

        if "agent_id" in publish_result:
            metadata.agent_id = publish_result["agent_id"]
        if "service_url" in publish_result:
            metadata.service_url = publish_result["service_url"]

        metadata_service.save_metadata(metadata)

import os
import json
import requests
from typing import Optional, Dict, Any
from pathlib import Path

from agentcube.services.metadata_service import MetadataService


class InvokeRuntime:
    def invoke(self, workspace: str, payload: Dict[str, Any], 
               headers: Optional[Dict[str, str]] = None,
               provider: str = "agentcube") -> Dict[str, Any]:
        workspace_path = Path(workspace).resolve()
        metadata_service = MetadataService(workspace_path)
        metadata = metadata_service.load_metadata()

        self._validate_invoke_prerequisites(metadata)

        if provider == "agentcube":
            result = self._invoke_agent_via_agentcube(metadata, payload, headers)
        elif provider == "k8s":
            result = self._direct_http_invocation(metadata, payload, headers)
        else:
            raise ValueError(f"Unsupported provider: {provider}")

        return result

    def _validate_invoke_prerequisites(self, metadata) -> None:
        if provider == "agentcube":
            if not metadata.router_url:
                raise ValueError("router_url is required in agent_metadata.yaml for agentcube provider")
        if not metadata.service_url and not metadata.router_url:
            raise ValueError("Agent is not published. Use 'agentcube publish' first.")

    def _invoke_agent_via_agentcube(self, metadata, payload: Dict[str, Any],
                                     headers: Optional[Dict[str, str]]) -> Dict[str, Any]:
        router_url = metadata.router_url or os.getenv("ROUTER_URL")
        if not router_url:
            raise ValueError("router_url must be provided in metadata or ROUTER_URL environment variable")

        workload_manager_url = metadata.workload_manager_url or os.getenv("WORKLOAD_MANAGER_URL")
        if not workload_manager_url:
            raise ValueError("workload_manager_url must be provided in metadata or WORKLOAD_MANAGER_URL environment variable")

        url = f"{router_url}/v1/namespaces/{metadata.namespace or 'default'}/agent-runtimes/{metadata.agent_name}/invocations/"

        if headers is None:
            headers = {}

        if metadata.session_id:
            headers["X-Agentcube-Session-Id"] = metadata.session_id

        headers["Content-Type"] = "application/json"

        response = requests.post(url, json=payload, headers=headers)
        response.raise_for_status()
        return response.json()

    def _direct_http_invocation(self, metadata, payload: Dict[str, Any],
                                 headers: Optional[Dict[str, str]]) -> Dict[str, Any]:
        service_url = metadata.service_url
        if not service_url:
            raise ValueError("Agent service_url is not set")

        if headers is None:
            headers = {}

        if metadata.session_id:
            headers["X-Agentcube-Session-Id"] = metadata.session_id

        headers["Content-Type"] = "application/json"

        response = requests.post(service_url, json=payload, headers=headers)
        response.raise_for_status()
        return response.json()

from typing import Optional, Dict, Any
from pathlib import Path

from agentcube.services.metadata_service import MetadataService
from agentcube.services.k8s_provider import KubernetesProvider
from agentcube.services.agentcube_provider import AgentCubeProvider


class StatusRuntime:
    def get_status(self, workspace: str, provider: str = "agentcube") -> Dict[str, Any]:
        workspace_path = Path(workspace).resolve()
        metadata_service = MetadataService(workspace_path)
        metadata = metadata_service.load_metadata()

        if provider == "agentcube":
            return self._get_cr_k8s_status(metadata)
        elif provider == "k8s":
            return self._get_k8s_status(metadata)
        else:
            raise ValueError(f"Unsupported provider: {provider}")

    def _get_k8s_status(self, metadata) -> Dict[str, Any]:
        if not metadata.agent_id and not metadata.deployment_name:
            return {"status": "not_published"}

        k8s_provider = KubernetesProvider()

        if metadata.deployment_name:
            status = k8s_provider.get_agent_status(
                deployment_name=metadata.deployment_name,
                namespace=metadata.namespace or "default",
            )
        else:
            status = {"status": "not_found_in_k8s"}

        return {
            "status": status.get("status", "unknown"),
            "deployment_name": metadata.deployment_name,
            "namespace": metadata.namespace,
            "replicas": status.get("replicas", 0),
            "available_replicas": status.get("available_replicas", 0),
            "service_url": metadata.service_url,
        }

    def _get_cr_k8s_status(self, metadata) -> Dict[str, Any]:
        if not metadata.agent_name:
            return {"status": "not_published"}

        agentcube_provider = AgentCubeProvider()
        cr_status = agentcube_provider.get_agent_runtime(
            name=metadata.agent_name,
            namespace=metadata.namespace or "default",
        )

        if not cr_status:
            return {"status": "not_found_in_k8s"}

        status_info = {
            "status": cr_status.get("status", "created_no_status"),
            "agent_name": metadata.agent_name,
            "namespace": metadata.namespace,
        }

        if "status" in cr_status:
            status_data = cr_status["status"]
            if "agentEndpoint" in status_data:
                status_info["agent_endpoint"] = status_data["agentEndpoint"]

        if "conditions" in cr_status:
            status_info["conditions"] = cr_status["conditions"]

        return status_info

import yaml
from typing import Optional, Dict, Any
from pathlib import Path
from pydantic import BaseModel, field_validator, model_validator


class AgentMetadata(BaseModel):
    agent_name: str
    language: str = "python"
    entrypoint: Optional[str] = None
    port: int = 8080
    build_mode: str = "local"
    description: Optional[str] = None
    version: Optional[str] = None
    image_url: Optional[str] = None
    router_url: Optional[str] = None
    workload_manager_url: Optional[str] = None
    service_url: Optional[str] = None
    agent_id: Optional[str] = None
    deployment_name: Optional[str] = None
    namespace: Optional[str] = None
    session_id: Optional[str] = None
    labels: Optional[Dict[str, str]] = None
    annotations: Optional[Dict[str, str]] = None
    env_vars: Optional[Dict[str, str]] = None

    @field_validator("language")
    @classmethod
    def validate_language(cls, v: str) -> str:
        supported = ["python", "java", "go", "nodejs", "rust"]
        if v.lower() not in supported:
            raise ValueError(f"Unsupported language: {v}. Supported: {', '.join(supported)}")
        return v.lower()

    @field_validator("build_mode")
    @classmethod
    def validate_build_mode(cls, v: str) -> str:
        supported = ["local", "cloud"]
        if v.lower() not in supported:
            raise ValueError(f"Unsupported build mode: {v}. Supported: {', '.join(supported)}")
        return v.lower()

    @field_validator("port")
    @classmethod
    def validate_port(cls, v: int) -> int:
        if v < 1 or v > 65535:
            raise ValueError(f"Port must be between 1 and 65535, got {v}")
        return v


class MetadataService:
    def __init__(self, workspace: Path):
        self.workspace = Path(workspace).resolve()
        self.metadata_files = ["agent_metadata.yaml", "agent.yaml", "metadata.yaml"]

    def load_metadata(self) -> AgentMetadata:
        for filename in self.metadata_files:
            metadata_path = self.workspace / filename
            if metadata_path.exists():
                with open(metadata_path, "r") as f:
                    data = yaml.safe_load(f)
                return AgentMetadata(**data)

        raise FileNotFoundError(f"No metadata file found in {self.workspace}")

    def save_metadata(self, metadata: AgentMetadata) -> None:
        metadata_path = self.workspace / "agent_metadata.yaml"

        with open(metadata_path, "w") as f:
            yaml.dump(
                metadata.model_dump(exclude_none=True),
                f,
                default_flow_style=False,
                indent=2,
                sort_keys=False,
            )

    def update_metadata(self, updates: Dict[str, Any]) -> AgentMetadata:
        metadata = self.load_metadata()

        for key, value in updates.items():
            if hasattr(metadata, key):
                setattr(metadata, key, value)

        self.save_metadata(metadata)
        return metadata

    def validate_workspace(self, language: Optional[str] = None) -> bool:
        if language is None:
            metadata = self.load_metadata()
            language = metadata.language

        if language == "python":
            return self._validate_python_workspace()
        elif language == "java":
            return self._validate_java_workspace()

        return True

    def _validate_python_workspace(self) -> bool:
        py_files = list(self.workspace.glob("*.py"))
        if not py_files:
            raise ValueError("No Python files found in workspace")
        return True

    def _validate_java_workspace(self) -> bool:
        pom_file = self.workspace / "pom.xml"
        if not pom_file.exists():
            raise ValueError("Java workspace must contain pom.xml")
        return True

import docker
from docker.errors import DockerException, ImageNotFound
from typing import Optional, Dict, Any
from datetime import datetime


class DockerService:
    def __init__(self):
        try:
            self.client = docker.from_env()
        except DockerException as e:
            raise RuntimeError(f"Failed to initialize Docker client: {e}")

    def check_docker_available(self) -> bool:
        try:
            self.client.ping()
            return True
        except DockerException:
            return False

    def build_image(self, path: str, tag: str, 
                    buildargs: Optional[Dict[str, str]] = None) -> Dict[str, Any]:
        try:
            build_time = datetime.now().isoformat()

            image, build_logs = self.client.images.build(
                path=path,
                tag=tag,
                buildargs=buildargs,
                rm=True,
            )

            image_info = self._get_image_info(image)

            return {
                "image_name": tag,
                "image_id": image.id,
                "image_size": image_info.get("size", 0),
                "build_time": build_time,
            }
        except DockerException as e:
            raise RuntimeError(f"Failed to build image: {e}")

    def get_image_info(self, image_name: str) -> Dict[str, Any]:
        try:
            image = self.client.images.get(image_name)
            return self._get_image_info(image)
        except ImageNotFound:
            raise RuntimeError(f"Image not found: {image_name}")

    def _get_image_info(self, image) -> Dict[str, Any]:
        attrs = image.attrs
        size = attrs.get("VirtualSize", 0)

        return {
            "id": image.id,
            "size": size,
            "size_human": self._format_size(size),
            "created": attrs.get("Created"),
            "tags": attrs.get("RepoTags", []),
        }

    def _format_size(self, size: int) -> str:
        for unit in ["B", "KB", "MB", "GB", "TB"]:
            if size < 1024.0:
                return f"{size:.2f} {unit}"
            size /= 1024.0
        return f"{size:.2f} PB"

    def push_image(self, image_name: str, registry_url: Optional[str] = None,
                   username: Optional[str] = None, password: Optional[str] = None) -> Dict[str, Any]:
        try:
            push_time = datetime.now().isoformat()

            if username and password:
                self._docker_login_sdk(registry_url, username, password)

            full_tag = self._tag_image_sdk(image_name, registry_url)

            push_logs = self.client.images.push(full_tag, stream=True, decode=True)

            for log in push_logs:
                if "error" in log:
                    raise RuntimeError(f"Push failed: {log['error']}")

            return {
                "pushed_image": full_tag,
                "push_time": push_time,
            }
        except DockerException as e:
            raise RuntimeError(f"Failed to push image: {e}")

    def _docker_login_sdk(self, registry_url: Optional[str], 
                          username: str, password: str) -> None:
        try:
            self.client.login(
                username=username,
                password=password,
                registry=registry_url,
            )
        except DockerException as e:
            raise RuntimeError(f"Docker login failed: {e}")

    def _tag_image_sdk(self, image_name: str, registry_url: Optional[str]) -> str:
        image = self.client.images.get(image_name)

        if registry_url:
            full_tag = f"{registry_url}/{image_name}"
        else:
            full_tag = image_name

        image.tag(full_tag)
        return full_tag

    def remove_image(self, image_name: str) -> bool:
        try:
            self.client.images.remove(image_name, force=False)
            return True
        except ImageNotFound:
            return False
        except DockerException as e:
            print(f"Warning: Failed to remove image {image_name}: {e}")
            return False

import time
from typing import Optional, Dict, Any
from kubernetes import client, config
from kubernetes.client.rest import ApiException


class KubernetesProvider:
    def __init__(self, kubeconfig: Optional[str] = None):
        try:
            config.load_kube_config(config_file=kubeconfig)
        except config.ConfigException:
            try:
                config.load_incluster_config()
            except config.ConfigException:
                raise RuntimeError("Failed to load Kubernetes config")

        self.apps_v1 = client.AppsV1Api()
        self.core_v1 = client.CoreV1Api()

    def _ensure_namespace(self, namespace: str) -> None:
        try:
            self.core_v1.read_namespace(name=namespace)
        except ApiException as e:
            if e.status == 404:
                try:
                    namespace_obj = client.V1Namespace(
                        metadata=client.V1ObjectMeta(name=namespace)
                    )
                    self.core_v1.create_namespace(body=namespace_obj)
                except ApiException as create_err:
                    raise RuntimeError(f"Failed to create namespace {namespace}: {create_err}")
            else:
                raise

    def deploy_agent(self, metadata, image: str, node_port: Optional[int] = None,
                     replicas: Optional[int] = None, namespace: str = "default") -> Dict[str, Any]:
        self._ensure_namespace(namespace)

        deployment_name = self._sanitize_name(f"{metadata.agent_name}-deployment")
        service_name = self._sanitize_name(f"{metadata.agent_name}-service")

        port = metadata.port or 8080

        deployment = self._create_deployment(
            name=deployment_name,
            namespace=namespace,
            image=image,
            port=port,
            replicas=replicas or 1,
            labels={"app": metadata.agent_name},
            annotations=metadata.annotations,
            env_vars=metadata.env_vars,
        )

        service = self._create_service(
            name=service_name,
            namespace=namespace,
            port=port,
            target_port=port,
            selector={"app": metadata.agent_name},
            node_port=node_port,
        )

        self.wait_for_deployment_ready(deployment_name, namespace, timeout=120)

        return {
            "deployment_name": deployment_name,
            "service_name": service_name,
            "namespace": namespace,
            "replicas": replicas or 1,
            "container_port": port,
            "node_port": node_port,
            "service_url": f"http://localhost:{node_port or port}",
        }

    def _create_deployment(self, name: str, namespace: str, image: str, 
                          port: int, replicas: int, labels: Dict[str, str],
                          annotations: Optional[Dict[str, str]] = None,
                          env_vars: Optional[Dict[str, str]] = None) -> Dict[str, Any]:
        container_env = []
        if env_vars:
            for key, value in env_vars.items():
                container_env.append(client.V1EnvVar(name=key, value=value))

        container = client.V1Container(
            name=name,
            image=image,
            ports=[client.V1ContainerPort(container_port=port)],
            env=container_env,
            resources=client.V1ResourceRequirements(
                requests={"cpu": "100m", "memory": "128Mi"},
                limits={"cpu": "500m", "memory": "512Mi"},
            ),
            liveness_probe=client.V1Probe(
                http_get=client.V1HTTPGetAction(path="/health", port=port),
                initial_delay_seconds=30,
                period_seconds=10,
            ),
            readiness_probe=client.V1Probe(
                http_get=client.V1HTTPGetAction(path="/health", port=port),
                initial_delay_seconds=10,
                period_seconds=5,
            ),
        )

        template = client.V1PodTemplateSpec(
            metadata=client.V1ObjectMeta(
                labels=labels,
                annotations=annotations,
            ),
            spec=client.V1PodSpec(
                containers=[container],
            ),
        )

        spec = client.V1DeploymentSpec(
            replicas=replicas,
            template=template,
            selector=client.V1LabelSelector(match_labels=labels),
        )

        deployment = client.V1Deployment(
            api_version="apps/v1",
            kind="Deployment",
            metadata=client.V1ObjectMeta(name=name, namespace=namespace),
            spec=spec,
        )

        try:
            return self.apps_v1.create_namespaced_deployment(namespace, body=deployment)
        except ApiException as e:
            raise RuntimeError(f"Failed to create deployment: {e}")

    def _create_service(self, name: str, namespace: str, port: int, 
                       target_port: int, selector: Dict[str, str],
                       node_port: Optional[int] = None) -> Dict[str, Any]:
        service = client.V1Service(
            api_version="v1",
            kind="Service",
            metadata=client.V1ObjectMeta(name=name, namespace=namespace),
            spec=client.V1ServiceSpec(
                type="NodePort" if node_port else "ClusterIP",
                ports=[client.V1ServicePort(
                    port=port,
                    target_port=target_port,
                    node_port=node_port,
                )],
                selector=selector,
            ),
        )

        try:
            return self.core_v1.create_namespaced_service(namespace, body=service)
        except ApiException as e:
            raise RuntimeError(f"Failed to create service: {e}")

    def wait_for_deployment_ready(self, deployment_name: str, namespace: str, 
                                  timeout: int = 120) -> None:
        start_time = time.time()

        while time.time() - start_time < timeout:
            try:
                deployment = self.apps_v1.read_namespaced_deployment(
                    name=deployment_name,
                    namespace=namespace,
                )

                if deployment.status.ready_replicas == deployment.spec.replicas:
                    return

                time.sleep(5)
            except ApiException as e:
                raise RuntimeError(f"Failed to check deployment status: {e}")

        raise TimeoutError(f"Deployment {deployment_name} not ready within {timeout} seconds")

    def get_agent_status(self, deployment_name: str, 
                        namespace: str) -> Dict[str, Any]:
        try:
            deployment = self.apps_v1.read_namespaced_deployment(
                name=deployment_name,
                namespace=namespace,
            )

            return {
                "status": "running",
                "replicas": deployment.spec.replicas,
                "available_replicas": deployment.status.available_replicas or 0,
                "updated_replicas": deployment.status.updated_replicas or 0,
                "conditions": deployment.status.conditions or [],
            }
        except ApiException as e:
            if e.status == 404:
                return {"status": "not_found"}
            raise RuntimeError(f"Failed to get agent status: {e}")

    def delete_agent(self, deployment_name: str, service_name: str, 
                    namespace: str) -> Dict[str, Any]:
        try:
            self.apps_v1.delete_namespaced_deployment(
                name=deployment_name,
                namespace=namespace,
            )
        except ApiException as e:
            if e.status != 404:
                print(f"Warning: Failed to delete deployment: {e}")

        try:
            self.core_v1.delete_namespaced_service(
                name=service_name,
                namespace=namespace,
            )
        except ApiException as e:
            if e.status != 404:
                print(f"Warning: Failed to delete service: {e}")

        return {
            "status": "deleted",
            "deployment_name": deployment_name,
            "namespace": namespace,
        }

    def _sanitize_name(self, name: str) -> str:
        import re
        sanitized = re.sub(r"[^a-z0-9-]", "-", name.lower())
        return sanitized[:63].rstrip("-")

from typing import Optional, Dict, Any
from kubernetes import client, config
from kubernetes.client.rest import ApiException
from kubernetes.client.api.custom_objects import CustomObjectsApi


class AgentCubeProvider:
    def __init__(self, kubeconfig: Optional[str] = None):
        try:
            config.load_kube_config(config_file=kubeconfig)
        except config.ConfigException:
            try:
                config.load_incluster_config()
            except config.ConfigException:
                raise RuntimeError("Failed to load Kubernetes config")

        self.api = CustomObjectsApi()
        self.core_v1 = client.CoreV1Api()

    def _ensure_namespace(self, namespace: str) -> None:
        try:
            self.core_v1.read_namespace(name=namespace)
        except ApiException as e:
            if e.status == 404:
                try:
                    namespace_obj = client.V1Namespace(
                        metadata=client.V1ObjectMeta(name=namespace)
                    )
                    self.core_v1.create_namespace(body=namespace_obj)
                except ApiException as create_err:
                    raise RuntimeError(f"Failed to create namespace {namespace}: {create_err}")
            else:
                raise

    def deploy_agent_runtime(self, metadata, image: str, 
                             namespace: Optional[str] = None) -> Dict[str, Any]:
        namespace = namespace or metadata.namespace or "default"
        self._ensure_namespace(namespace)

        agent_name = self._sanitize_name(metadata.agent_name)

        router_url = metadata.router_url or "http://router:8080"
        workload_manager_url = metadata.workload_manager_url or "http://workload-manager:8080"

        if metadata.env_vars is None:
            metadata.env_vars = {}

        metadata.env_vars.setdefault("ROUTER_URL", router_url)
        metadata.env_vars.setdefault("WORKLOAD_MANAGER_URL", workload_manager_url)

        env_list = [client.V1EnvVar(name=k, value=v) for k, v in metadata.env_vars.items()]

        pod_spec = client.V1PodSpec(
            containers=[client.V1Container(
                name=agent_name,
                image=image,
                ports=[client.V1ContainerPort(container_port=metadata.port or 8080)],
                env=env_list,
            )],
        )

        if metadata.image_pull_secrets:
            pod_spec.image_pull_secrets = [
                client.V1LocalObjectReference(name=s) 
                for s in metadata.image_pull_secrets
            ]

        cr = {
            "apiVersion": "runtime.agentcube.volcano.sh/v1alpha1",
            "kind": "AgentRuntime",
            "metadata": {
                "name": agent_name,
                "namespace": namespace,
                "labels": metadata.labels,
                "annotations": metadata.annotations,
            },
            "spec": {
                "targetPort": [{
                    "port": metadata.port or 8080,
                    "protocol": "HTTP",
                }],
                "podTemplate": {
                    "spec": pod_spec,
                },
                "sessionTimeout": "15m",
                "maxSessionDuration": "8h",
            },
        }

        try:
            self.api.create_namespaced_custom_object(
                group="runtime.agentcube.volcano.sh",
                version="v1alpha1",
                namespace=namespace,
                plural="agentruntimes",
                body=cr,
            )
        except ApiException as e:
            if e.status == 409:
                self.api.patch_namespaced_custom_object(
                    group="runtime.agentcube.volcano.sh",
                    version="v1alpha1",
                    namespace=namespace,
                    plural="agentruntimes",
                    name=agent_name,
                    body=cr,
                )
            else:
                raise RuntimeError(f"Failed to create AgentRuntime CR: {e}")

        return {
            "agent_id": agent_name,
            "status": "created",
            "namespace": namespace,
        }

    def get_agent_runtime(self, name: str, namespace: str) -> Optional[Dict[str, Any]]:
        try:
            cr = self.api.get_namespaced_custom_object(
                group="runtime.agentcube.volcano.sh",
                version="v1alpha1",
                namespace=namespace,
                plural="agentruntimes",
                name=name,
            )
            return cr
        except ApiException as e:
            if e.status == 404:
                return None
            raise RuntimeError(f"Failed to get AgentRuntime CR: {e}")

    def _sanitize_name(self, name: str) -> str:
        import re
        sanitized = re.sub(r"[^a-z0-9-]", "-", name.lower())
        return sanitized[:63].rstrip("-")

