        if provider == "agentcube":
            if not metadata.router_url:
                raise ValueError("router_url is required in agent_metadata.yaml for agentcube provider")
        if not metadata.service_url and not metadata.router_url:
            raise ValueError("Agent is not published. Use 'agentcube publish' first.")

    def _invoke_agent_via_agentcube(self, metadata, payload: Dict[str, Any],
                                     headers: Optional[Dict[str, str]]) -> Dict[str, Any]:
        router_url = metadata.router_url or os.getenv("ROUTER_URL")
        if not router_url:
            raise ValueError("router_url must be provided in metadata or ROUTER_URL environment variable")

        workload_manager_url = metadata.workload_manager_url or os.getenv("WORKLOAD_MANAGER_URL")
        if not workload_manager_url:
            raise ValueError("workload_manager_url must be provided in metadata or WORKLOAD_MANAGER_URL environment variable")

        url = f"{router_url}/v1/namespaces/{metadata.namespace or 'default'}/agent-runtimes/{metadata.agent_name}/invocations/"

        if headers is None:
            headers = {}

        if metadata.session_id:
            headers["X-Agentcube-Session-Id"] = metadata.session_id

        headers["Content-Type"] = "application/json"

        response = requests.post(url, json=payload, headers=headers)
        response.raise_for_status()
        return response.json()

    def _direct_http_invocation(self, metadata, payload: Dict[str, Any],
                                 headers: Optional[Dict[str, str]]) -> Dict[str, Any]:
        service_url = metadata.service_url
        if not service_url:
            raise ValueError("Agent service_url is not set")

        if headers is None:
            headers = {}

        if metadata.session_id:
            headers["X-Agentcube-Session-Id"] = metadata.session_id

        headers["Content-Type"] = "application/json"

        response = requests.post(service_url, json=payload, headers=headers)
        response.raise_for_status()
        return response.json()

