import sys

def add(a: int, b: int) -> int:
    return a + b

def multiply(a: int, b: int) -> int:
    return a * b

if __name__ == "__main__":
    if len(sys.argv) < 4:
        print("Usage: python main.py <add|multiply> <num1> <num2>")
        sys.exit(1)

    operation = sys.argv[1]
    num1 = int(sys.argv[2])
    num2 = int(sys.argv[3])

    if operation == "add":
        result = add(num1, num2)
        print(f"{num1} + {num2} = {result}")
    elif operation == "multiply":
        result = multiply(num1, num2)
        print(f"{num1} * {num2} = {result}")
    else:
        print(f"Unknown operation: {operation}")
        sys.exit(1)

package picod

import (
	"crypto/rsa"
	"errors"
	"net/http"
	"os"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"k8s.io/klog/v2"
)

const (
	TimeoutExitCode   = 124
	MaxBodySize       = 32 << 20
	PublicKeyEnvVar   = "PICOD_AUTH_PUBLIC_KEY"
	maxFileMode       = 0777
	DefaultPort       = "8080"
	DefaultReadHeaderTimeout = 10 * time.Second
)

type Server struct {
	engine      *gin.Engine
	config      *Config
	authManager *AuthManager
	startTime   time.Time
	workspaceDir string
	mu          sync.RWMutex
}

func NewServer(config *Config) (*Server, error) {
	if err := os.Setenv(gin.EnvGinMode, gin.ReleaseMode); err != nil {
		return nil, err
	}

	gin.SetMode(gin.ReleaseMode)
	engine := gin.New()
	engine.Use(gin.Logger())
	engine.Use(gin.Recovery())

	authManager := &AuthManager{}
	if err := authManager.LoadPublicKeyFromEnv(); err != nil {
		return nil, err
	}

	workspaceDir := config.Workspace
	if workspaceDir == "" {
		wd, err := os.Getwd()
		if err != nil {
			return nil, err
		}
		workspaceDir = wd
	}

	server := &Server{
		engine:      engine,
		config:      config,
		authManager: authManager,
		startTime:   time.Now(),
		workspaceDir: workspaceDir,
	}

	server.registerRoutes()

	return server, nil
}

func (s *Server) Run() error {
	port := s.config.Port
	if port == "" {
		port = DefaultPort
	}

	srv := &http.Server{
		Addr:              ":" + port,
		Handler:           s.engine,
		ReadHeaderTimeout: DefaultReadHeaderTimeout,
	}

	klog.Infof("Starting PicoD server on port %s", port)
	klog.Infof("Workspace directory: %s", s.workspaceDir)

	return srv.ListenAndServe()
}

func (s *Server) setWorkspace(path string) error {
	absPath, err := s.resolvePath(path)
	if err != nil {
		return err
	}

	if _, err := os.Stat(absPath); err != nil {
		return err
	}

	s.mu.Lock()
	s.workspaceDir = absPath
	s.mu.Unlock()

	return nil
}

func (s *Server) resolvePath(path string) (string, error) {
	if path == "" {
		return os.Getwd()
	}
	return filepath.Abs(path)
}

func (s *Server) HealthCheckHandler(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{
		"status":   "ok",
		"service":  "PicoD",
		"version":  "0.0.1",
		"uptime":   time.Since(s.startTime).String(),
	})
}

func (s *Server) registerRoutes() {
	publicGroup := s.engine.Group("/")
	publicGroup.GET("/health", s.HealthCheckHandler)

	apiGroup := s.engine.Group("/api")
	apiGroup.Use(s.authManager.AuthMiddleware())

	apiGroup.POST("/execute", s.ExecuteHandler)
	apiGroup.POST("/files", s.UploadFileHandler)
	apiGroup.GET("/files", s.ListFilesHandler)
	apiGroup.GET("/files/*path", s.DownloadFileHandler)
}

package picod

type Config struct {
	Port      string `json:"port"`
	Workspace string `json:"workspace"`
}

package picod

import (
	"encoding/base64"
	"fmt"
	"io"
	"net/http"
	"os"
	"path/filepath"
	"strconv"
	"time"

	"github.com/gin-gonic/gin"
)

type FileInfo struct {
	Path     string    `json:"path"`
	Size     int64     `json:"size"`
	Mode     string    `json:"mode"`
	Modified string    `json:"modified"`
}

type UploadFileRequest struct {
	Path    string `json:"path"`
	Content string `json:"content"`
	Mode    string `json:"mode"`
}

type FileEntry struct {
	Name     string    `json:"name"`
	Size     int64     `json:"size"`
	Modified string    `json:"modified"`
	Mode     string    `json:"mode"`
	IsDir    bool      `json:"is_dir"`
}

type ListFilesResponse struct {
	Files []FileEntry `json:"files"`
}

func (s *Server) UploadFileHandler(c *gin.Context) {
	s.mu.RLock()
	workspace := s.workspaceDir
	s.mu.RUnlock()

	contentType := c.GetHeader("Content-Type")

	if strings.HasPrefix(contentType, "multipart/form-data") {
		s.handleMultipartUpload(c, workspace)
	} else {
		s.handleJSONBase64Upload(c, workspace)
	}
}

func (s *Server) handleMultipartUpload(c *gin.Context, workspace string) {
	path := c.PostForm("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "path is required",
			"code":  400,
		})
		return
	}

	file, err := c.FormFile("file")
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("file upload error: %v", err),
			"code":  400,
		})
		return
	}

	sanitizedPath, err := sanitizePath(path, workspace)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("invalid path: %v", err),
			"code":  400,
		})
		return
	}

	if err := os.MkdirAll(filepath.Dir(sanitizedPath), 0755); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to create directory: %v", err),
			"code":  500,
		})
		return
	}

	src, err := file.Open()
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to open uploaded file: %v", err),
			"code":  500,
		})
		return
	}
	defer src.Close()

	dst, err := os.Create(sanitizedPath)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to create file: %v", err),
			"code":  500,
		})
		return
	}
	defer dst.Close()

	if _, err := io.Copy(dst, src); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to write file: %v", err),
			"code":  500,
		})
		return
	}

	modeStr := c.PostForm("mode")
	mode := parseFileMode(modeStr)
	if err := os.Chmod(sanitizedPath, os.FileMode(mode)); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to set file mode: %v", err),
			"code":  500,
		})
		return
	}

	info, _ := os.Stat(sanitizedPath)
	response := FileInfo{
		Path:     path,
		Size:     info.Size(),
		Mode:     fmt.Sprintf("%04o", mode),
		Modified: info.ModTime().Format(time.RFC3339),
	}

	c.JSON(http.StatusOK, response)
}

func (s *Server) handleJSONBase64Upload(c *gin.Context, workspace string) {
	var req UploadFileRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": err.Error(),
			"code":  400,
		})
		return
	}

	if req.Path == "" {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "path is required",
			"code":  400,
		})
		return
	}

	content, err := base64.StdEncoding.DecodeString(req.Content)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("invalid base64 content: %v", err),
			"code":  400,
		})
		return
	}

	sanitizedPath, err := sanitizePath(req.Path, workspace)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("invalid path: %v", err),
			"code":  400,
		})
		return
	}

	if err := os.MkdirAll(filepath.Dir(sanitizedPath), 0755); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to create directory: %v", err),
			"code":  500,
		})
		return
	}

	if err := os.WriteFile(sanitizedPath, content, 0644); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to write file: %v", err),
			"code":  500,
		})
		return
	}

	mode := parseFileMode(req.Mode)
	if err := os.Chmod(sanitizedPath, os.FileMode(mode)); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to set file mode: %v", err),
			"code":  500,
		})
		return
	}

	info, _ := os.Stat(sanitizedPath)
	response := FileInfo{
		Path:     req.Path,
		Size:     info.Size(),
		Mode:     fmt.Sprintf("%04o", mode),
		Modified: info.ModTime().Format(time.RFC3339),
	}

	c.JSON(http.StatusOK, response)
}

func (s *Server) ListFilesHandler(c *gin.Context) {
	s.mu.RLock()
	workspace := s.workspaceDir
	s.mu.RUnlock()

	path := c.Query("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Missing 'path' query parameter",
			"code":  400,
		})
		return
	}

	sanitizedPath, err := sanitizePath(path, workspace)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("invalid path: %v", err),
			"code":  400,
		})
		return
	}

	entries, err := os.ReadDir(sanitizedPath)
	if err != nil {
		if os.IsNotExist(err) {
			c.JSON(http.StatusNotFound, gin.H{
				"error": "Directory not found",
				"code":  404,
			})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to read directory: %v", err),
			"code":  500,
		})
		return
	}

	var files []FileEntry
	for _, entry := range entries {
		info, err := entry.Info()
		if err != nil {
			continue
		}

		files = append(files, FileEntry{
			Name:     entry.Name(),
			Size:     info.Size(),
			Modified: info.ModTime().Format(time.RFC3339),
			Mode:     fmt.Sprintf("%04o", info.Mode().Perm()),
			IsDir:    entry.IsDir(),
		})
	}

	response := ListFilesResponse{
		Files: files,
	}

	c.JSON(http.StatusOK, response)
}

func (s *Server) DownloadFileHandler(c *gin.Context) {
	s.mu.RLock()
	workspace := s.workspaceDir
	s.mu.RUnlock()

	path := c.Param("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "path is required",
			"code":  400,
		})
		return
	}

	sanitizedPath, err := sanitizePath(path, workspace)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("access denied: path outside workspace"),
			"code":  400,
		})
		return
	}

	info, err := os.Stat(sanitizedPath)
	if err != nil {
		if os.IsNotExist(err) {
			c.JSON(http.StatusNotFound, gin.H{
				"error": "File not found",
				"code":  404,
			})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to stat file: %v", err),
			"code":  500,
		})
		return
	}

	if info.IsDir() {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Path is a directory, not a file",
			"code":  400,
		})
		return
	}

	c.Header("Content-Description", "File Transfer")
	c.Header("Content-Transfer-Encoding", "binary")
	c.Header("Content-Disposition", fmt.Sprintf("attachment; filename=\"%s\"", filepath.Base(path)))
	c.Header("Content-Type", "application/octet-stream")

	c.File(sanitizedPath)
}

func parseFileMode(modeStr string) uint32 {
	if modeStr == "" {
		return 0644
	}

	mode, err := strconv.ParseUint(modeStr, 8, 32)
	if err != nil {
		return 0644
	}

	if mode > uint64(maxFileMode) {
		return 0644
	}

	return uint32(mode)
}

package picod

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"os"
	"os/exec"
	"path/filepath"
	"strconv"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
	"k8s.io/klog/v2"
)

type ExecuteRequest struct {
	Command     []string          `json:"command"`
	Timeout     string            `json:"timeout"`
	WorkingDir  string            `json:"working_dir"`
	Env         map[string]string `json:"env"`
}

type ExecuteResponse struct {
	Stdout     string        `json:"stdout"`
	Stderr     string        `json:"stderr"`
	ExitCode   int           `json:"exit_code"`
	Duration   float64       `json:"duration"`
	StartTime  string        `json:"start_time"`
	EndTime    string        `json:"end_time"`
}

func (s *Server) ExecuteHandler(c *gin.Context) {
	var req ExecuteRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": err.Error(),
			"code":  400,
		})
		return
	}

	if len(req.Command) == 0 {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "command cannot be empty",
			"code":  400,
		})
		return
	}

	timeout := 60 * time.Second
	if req.Timeout != "" {
		parsedTimeout, err := time.ParseDuration(req.Timeout)
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{
				"error": fmt.Sprintf("invalid timeout format: %v", err),
				"code":  400,
			})
			return
		}
		timeout = parsedTimeout
	}

	ctx, cancel := context.WithTimeout(context.Background(), timeout)
	defer cancel()

	cmd := exec.CommandContext(ctx, req.Command[0], req.Command[1:]...)

	if req.WorkingDir != "" {
		s.mu.RLock()
		absWorkspace := s.workspaceDir
		s.mu.RUnlock()

		sanitizedDir, err := sanitizePath(req.WorkingDir, absWorkspace)
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{
				"error": fmt.Sprintf("Invalid working directory: %v", err),
				"code":  400,
			})
			return
		}
		cmd.Dir = sanitizedDir
	}

	cmd.Env = os.Environ()
	for k, v := range req.Env {
		cmd.Env = append(cmd.Env, fmt.Sprintf("%s=%s", k, v))
	}

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	startTime := time.Now()
	err := cmd.Run()
	endTime := time.Now()

	exitCode := 0
	if err != nil {
		if ctx.Err() == context.DeadlineExceeded {
			exitCode = TimeoutExitCode
			stderr.WriteString(fmt.Sprintf("\nCommand timed out after %d seconds\n", int(timeout.Seconds())))
		} else if exitErr, ok := err.(*exec.ExitError); ok {
			exitCode = exitErr.ExitCode()
		} else {
			exitCode = 1
		}
	}

	response := ExecuteResponse{
		Stdout:    stdout.String(),
		Stderr:    stderr.String(),
		ExitCode:  exitCode,
		Duration:  endTime.Sub(startTime).Seconds(),
		StartTime: startTime.Format(time.RFC3339),
		EndTime:   endTime.Format(time.RFC3339),
	}

	c.JSON(http.StatusOK, response)
}

package main

import (
	"flag"

	"github.com/volcano-sh/agentcube/pkg/picod"
	"k8s.io/klog/v2"
)

func main() {
	port := flag.String("port", "", "Port to listen on")
	workspace := flag.String("workspace", "", "Workspace directory path")
	flag.Parse()

	klog.InitFlags(nil)

	config := &picod.Config{
		Port:      *port,
		Workspace: *workspace,
	}

	server, err := picod.NewServer(config)
	if err != nil {
		klog.Fatalf("Failed to create server: %v", err)
	}

	if err := server.Run(); err != nil {
		klog.Fatalf("Server error: %v", err)
	}
}

package picod

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"
)

func sanitizePath(path string, workspace string) (string, error) {
	if workspace == "" {
		return "", fmt.Errorf("workspace is empty")
	}

	absWorkspace, err := filepath.Abs(workspace)
	if err != nil {
		return "", fmt.Errorf("failed to resolve workspace: %v", err)
	}

	inputPath := path
	if !filepath.IsAbs(inputPath) {
		inputPath = filepath.Join(absWorkspace, inputPath)
	}

	absPath, err := filepath.Abs(inputPath)
	if err != nil {
		return "", fmt.Errorf("failed to resolve path: %v", err)
	}

	absPath = filepath.Clean(absPath)
	absWorkspace = filepath.Clean(absWorkspace)

	relPath, err := filepath.Rel(absWorkspace, absPath)
	if err != nil {
		return "", fmt.Errorf("failed to compute relative path: %v", err)
	}

	if strings.HasPrefix(relPath, "..") || strings.HasPrefix(relPath, "../") {
		return "", fmt.Errorf("path escapes workspace: %s", path)
	}

	return absPath, nil
}

package picod

import (
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"errors"
	"fmt"
	"net/http"
	"os"
	"sync"

	"github.com/gin-gonic/gin"
	"github.com/golang-jwt/jwt/v5"
	"k8s.io/klog/v2"
)

type AuthManager struct {
	publicKey *rsa.PublicKey
	privateKey *rsa.PrivateKey
	mu       sync.RWMutex
}

func (am *AuthManager) LoadPublicKeyFromEnv() error {
	pubKeyPEM := os.Getenv(PublicKeyEnvVar)
	if pubKeyPEM == "" {
		return fmt.Errorf("%s environment variable is not set", PublicKeyEnvVar)
	}

	block, _ := pem.Decode([]byte(pubKeyPEM))
	if block == nil {
		return errors.New("failed to decode PEM block containing public key")
	}

	pub, err := x509.ParsePKIXPublicKey(block.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse public key: %v", err)
	}

	rsaPub, ok := pub.(*rsa.PublicKey)
	if !ok {
		return errors.New("public key is not an RSA key")
	}

	am.mu.Lock()
	am.publicKey = rsaPub
	am.mu.Unlock()

	return nil
}

func (am *AuthManager) GenerateToken(claims jwt.MapClaims) (string, error) {
	am.mu.RLock()
	privateKey := am.privateKey
	am.mu.RUnlock()

	if privateKey == nil {
		return "", errors.New("private key not available")
	}

	token := jwt.NewWithClaims(jwt.SigningMethodRS256, claims)
	return token.SignedString(privateKey)
}

func (am *AuthManager) AuthMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.JSON(http.StatusUnauthorized, gin.H{
				"error":  "missing authorization header",
				"code":   401,
				"detail": "Authorization header is required",
			})
			c.Abort()
			return
		}

		parts := len(authHeader)
		if parts != 2 || authHeader[:7] != "Bearer " {
			c.JSON(http.StatusUnauthorized, gin.H{
				"error":  "invalid authorization header format",
				"code":   401,
				"detail": "Expected 'Bearer <token>'",
			})
			c.Abort()
			return
		}

		tokenString := authHeader[7:]

		token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
			if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
				return nil, fmt.Errorf("unexpected signing method: %v", token.Header["alg"])
			}

			am.mu.RLock()
			publicKey := am.publicKey
			am.mu.RUnlock()

			return publicKey, nil
		})

		if err != nil || !token.Valid {
			c.JSON(http.StatusUnauthorized, gin.H{
				"error":  "Invalid token",
				"code":   401,
				"detail": err.Error(),
			})
			c.Abort()
			return
		}

		c.Request.Body = http.MaxBytesReader(c.Writer, c.Request.Body, MaxBodySize)
		c.Next()
	}
}

package picod

import (
	"fmt"
	"io"
	"mime/multipart"
	"net/http"
	"os"

	"github.com/gin-gonic/gin"
)

func handleMultipartUpload(c *gin.Context, workspace string) {
	path := c.PostForm("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "path is required",
			"code":  400,
		})
		return
	}

	fileHeader, err := c.FormFile("file")
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("file upload error: %v", err),
			"code":  400,
		})
		return
	}

	file, err := fileHeader.Open()
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to open uploaded file: %v", err),
			"code":  500,
		})
		return
	}
	defer file.Close()

	sanitizedPath, err := sanitizePath(path, workspace)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("invalid path: %v", err),
			"code":  400,
		})
		return
	}

	if err := os.MkdirAll(filepath.Dir(sanitizedPath), 0755); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to create directory: %v", err),
			"code":  500,
		})
		return
	}

	dst, err := os.Create(sanitizedPath)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to create file: %v", err),
			"code":  500,
		})
		return
	}
	defer dst.Close()

	if _, err := io.Copy(dst, file); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to write file: %v", err),
			"code":  500,
		})
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "file uploaded successfully"})
}

func handleJSONBase64Upload(c *gin.Context, workspace string) {
	var req UploadFileRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": err.Error(),
			"code":  400,
		})
		return
	}

	if req.Path == "" {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "path is required",
			"code":  400,
		})
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "file uploaded successfully"})
}

