const (
	rsaKeySize         = 2048
	jwtExpiration     = 5 * time.Minute
	IdentitySecretName = "picod-router-identity"
	PrivateKeyDataKey   = "private.pem"
	PublicKeyDataKey    = "public.pem"
)

type JWTManager struct {
	privateKey *rsa.PrivateKey
	publicKey  *rsa.PublicKey
	clientset  *kubernetes.Clientset
}

func NewJWTManager(clientset *kubernetes.Clientset) (*JWTManager, error) {
	key, err := rsa.GenerateKey(rand.Reader, rsaKeySize)
	if err != nil {
		return nil, fmt.Errorf("failed to generate RSA key: %v", err)
	}

	manager := &JWTManager{
		privateKey: key,
		publicKey:  &key.PublicKey,
		clientset:  clientset,
	}

	if err := manager.TryStoreOrLoadJWTKeySecret(); err != nil {
		return nil, err
	}

	return manager, nil
}

func (jm *JWTManager) GenerateToken(claims jwt.MapClaims) (string, error) {
	claims["exp"] = time.Now().Add(jwtExpiration).Unix()
	claims["iat"] = time.Now().Unix()

	token := jwt.NewWithClaims(jwt.SigningMethodRS256, claims)
	return token.SignedString(jm.privateKey)
}

func (jm *JWTManager) TryStoreOrLoadJWTKeySecret() error {
	namespace := "default"
	if ns := os.Getenv("AGENTCUBE_NAMESPACE"); ns != "" {
		namespace = ns
	}

	secret, err := jm.clientset.CoreV1().Secrets(namespace).Get(jm.ctx, IdentitySecretName, metav1.GetOptions{})
	if err == nil {
		return jm.loadPrivateKeyPEM(secret.Data[PrivateKeyDataKey])
	}

	if !errors.IsNotFound(err) {
		return fmt.Errorf("failed to get secret: %v", err)
	}

	privateKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: x509.MarshalPKCS1PrivateKey(jm.privateKey),
	})

	publicKeyBytes, err := x509.MarshalPKIXPublicKey(jm.publicKey)
	if err != nil {
		return fmt.Errorf("failed to marshal public key: %v", err)
	}

	publicKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "RSA PUBLIC KEY",
		Bytes: publicKeyBytes,
	})

	newSecret := &corev1.Secret{
		ObjectMeta: metav1.ObjectMeta{
			Name:      IdentitySecretName,
			Namespace: namespace,
		},
		Data: map[string][]byte{
			PrivateKeyDataKey: privateKeyPEM,
			PublicKeyDataKey:  publicKeyPEM,
		},
		Type: corev1.SecretTypeOpaque,
	}

	_, err = jm.clientset.CoreV1().Secrets(namespace).Create(jm.ctx, newSecret, metav1.CreateOptions{})
	return err
}

func (jm *JWTManager) loadPrivateKeyPEM(data []byte) error {
	block, _ := pem.Decode(data)
	if block == nil {
		return fmt.Errorf("failed to decode PEM block")
	}

	key, err := x509.ParsePKCS1PrivateKey(block.Bytes)
	if err != nil {
		return err
	}

	jm.privateKey = key
	jm.publicKey = &key.PublicKey
	return nil
}
